def gen(rng, size):
    depth = max(1, size)
    letters = 'abc'
    def build(d, budget):
        if d <= 0 or budget <= 1 or rng.random() < 0.4:
            return rng.choice(letters)
        choice = rng.random()
        if choice < 0.5:
            k = rng.randrange(2, 4)
            parts = [build(d - 1, budget // k) for _ in range(k)]
            return '{' + ','.join(parts) + '}'
        else:
            k = rng.randrange(2, 3)
            parts = [build(d - 1, budget // k) for _ in range(k)]
            return ''.join(parts)
    e = build(depth, 30)
    return [e]

