class Solution:
    def braceExpansionII(self, expression):
        def parse(s):
            # returns set of words for a top-level expression (union of concat groups)
            groups = split_top(s, ',')
            result = set()
            for g in groups:
                result |= concat(g)
                pass
            return result
        def concat(s):
            factors = split_factors(s)
            cur = {''}
            for f in factors:
                fset = factor_set(f)
                cur = {a + b for a in cur for b in fset}
            return cur
        def factor_set(f):
            if f and f[0] == '{':
                return parse(f[1:-1])
            return {f}
        def split_top(s, sep):
            parts = []
            depth = 0
            last = 0
            for i, ch in enumerate(s):
                if ch == '{':
                    depth += 1
                elif ch == '}':
                    depth -= 1
                elif ch == sep and depth == 0:
                    parts.append(s[last:i])
                    last = i + 1
            parts.append(s[last:])
            return parts
        def split_factors(s):
            factors = []
            depth = 0
            i = 0
            n = len(s)
            while i < n:
                if s[i] == '{':
                    j = i
                    d = 0
                    while j < n:
                        if s[j] == '{':
                            d += 1
                        elif s[j] == '}':
                            d -= 1
                            if d == 0:
                                break
                        j += 1
                    factors.append(s[i:j + 1])
                    i = j + 1
                else:
                    j = i
                    while j < n and s[j] != '{':
                        j += 1
                    factors.append(s[i:j])
                    i = j
            return factors
        return sorted(parse(expression))

