class Solution:
    def braceExpansionII(self, expression):
        pos = 0
        s = expression
        n = len(s)
        def parse_union():
            nonlocal pos
            result = set()
            result |= parse_concat()
            while pos < n and s[pos] == ',':
                pos += 1
                result |= parse_concat()
            return result
        def parse_concat():
            nonlocal pos
            cur = {''}
            while pos < n and s[pos] not in ',}':
                if s[pos] == '{':
                    pos += 1
                    inner = parse_union()
                    pos += 1
                    cur = {a + b for a in cur for b in inner}
                else:
                    cur = {a + s[pos] for a in cur}
                    pos += 1
            return cur
        return sorted(parse_union())

