var braceExpansionII = function(expression) {
    let pos = 0;
    const s = expression;
    const n = s.length;
    function parseUnion() {
        let result = new Set(parseConcat());
        while (pos < n && s[pos] === ',') {
            pos++;
            for (const w of parseConcat()) result.add(w);
        }
        return result;
    }
    function parseConcat() {
        let cur = new Set(['']);
        while (pos < n && s[pos] !== ',' && s[pos] !== '}') {
            if (s[pos] === '{') {
                pos++;
                const inner = parseUnion();
                pos++;
                const next = new Set();
                for (const a of cur) for (const b of inner) next.add(a + b);
                cur = next;
            } else {
                const ch = s[pos];
                const next = new Set();
                for (const a of cur) next.add(a + ch);
                cur = next;
                pos++;
            }
        }
        return cur;
    }
    const result = parseUnion();
    return Array.from(result).sort();
};
